var hasAlternatingBits = function(n) {
    let prev = n & 1;
    n = Math.floor(n / 2);
    while (n > 0) {
        const cur = n & 1;
        if (cur === prev) return false;
        prev = cur;
        n = Math.floor(n / 2);
    }
    return true;
};
